import React, { useEffect, useState } from "react";
import {
  Box,
  Flex,
  Heading,
  Text,
  Image,
  Button,
} from "@chakra-ui/react";
import { useParams } from "react-router-dom";
import { useDisclosure } from "@chakra-ui/react";
import { useSelector } from "react-redux";
import { AiOutlineLock } from "react-icons/ai";

import Navbar from "../UserComponents/UserNavbar";
import Footer from "../../Pages/Footer";
import SingleAbsolute from "./SingleAbsolute";
import SingleList from "./SingleList";
import Payment from "../../Pages/Payment/Payment";

import convertDateFormat from "../../Redux/AdminReducer/action";
import { capitalizeFirstLetter } from "../../Redux/UserReducer/action";

export default function SinglePage() {
  const [res, setRes] = useState({});
  const { id } = useParams();
  const userStore = useSelector((store) => store.UserReducer);

  const { isOpen, onOpen, onClose } = useDisclosure();

  const vdo_url = `https://elearning-platform-using-mern-j5py.vercel.app/videos/courseVideos/${id}`;

  const getSinglePageData = () => {
    fetch(vdo_url, {
      headers: {
        "Content-Type": "application/json",
        authorization: `Bearer ${userStore?.token}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setRes(data))
      .catch((err) => console.log(err));
  };

  useEffect(() => {
    getSinglePageData();
  }, [id]);

  return (
    <>
      <Navbar />

      {/* HERO */}
      <Box bg="#1c1d1f" color="white" py={10}>
        <Flex maxW="1100px" mx="auto" px={5} gap={10}>
          
          {/* LEFT */}
          <Box flex="2">
            <Heading mb={3}>
              {res?.course?.title || "Course Name"}
            </Heading>

            <Text color="gray.300" mb={3}>
              {res?.course?.description}
            </Text>

            <Text fontSize="sm" mb={2}>
              ⭐ 4.8 (12,866 ratings) • 69,107 students
            </Text>

            <Text fontSize="sm">
              Created by{" "}
              <Text as="span" color="#A435F0" fontWeight="bold">
                {res?.course?.teacher}
              </Text>
            </Text>

            <Text fontSize="sm" mt={2} color="gray.400">
              Last updated {convertDateFormat(res?.course?.createdAt)}
            </Text>
          </Box>

          {/* RIGHT (STICKY CARD) */}
          <Box flex="1" display={{ base: "none", md: "block" }}>
            <Box position="sticky" top="100px">
              <SingleAbsolute props={{ ...res?.course, onOpen }} />
            </Box>
          </Box>
        </Flex>
      </Box>

      {/* MAIN */}
      <Flex maxW="1100px" mx="auto" mt={10} px={5} gap={10}>
        
        {/* LEFT CONTENT */}
        <Box flex="2">
          <SingleList />

          {/* COURSE INFO */}
          <Box mt={10}>
            <Heading size="md" mb={4}>
              Course Info
            </Heading>

            <Text mb={2}>
              <b>Teacher:</b>{" "}
              {capitalizeFirstLetter(res?.course?.teacher)}
            </Text>

            <Text mb={2}>
              <b>Created:</b>{" "}
              {convertDateFormat(res?.course?.createdAt)}
            </Text>

            <Text mb={2}>
              <b>Total Videos:</b>{" "}
              {res?.course?.videos?.length || 0}
            </Text>
          </Box>

          {/* VIDEO LIST */}
          <Box mt={10}>
            <Heading size="md" mb={5}>
              Course Content
            </Heading>

            {res?.course?.videos?.length ? (
              res.course.videos.map((video, index) => (
                <Flex
                  key={index}
                  border="1px solid #e5e7eb"
                  borderRadius="md"
                  p={4}
                  mb={4}
                  gap={4}
                  align="center"
                  _hover={{ bg: "#f7f9fa" }}
                >
                  {/* IMAGE */}
                  <Box position="relative" w="180px">
                    <Image
                      src={video?.img}
                      borderRadius="md"
                    />
                    <Box
                      position="absolute"
                      top="50%"
                      left="50%"
                      transform="translate(-50%, -50%)"
                    >
                      <AiOutlineLock size={30} color="#A435F0" />
                    </Box>
                  </Box>

                  {/* INFO */}
                  <Box flex="1">
                    <Text fontWeight="bold">
                      {video?.title}
                    </Text>

                    <Text fontSize="sm" color="gray.600">
                      {video?.description}
                    </Text>

                    <Text fontSize="xs" mt={2}>
                      Instructor:{" "}
                      {capitalizeFirstLetter(video?.teacher)}
                    </Text>

                    <Text fontSize="xs">
                      {convertDateFormat(video?.createdAt)}
                    </Text>
                  </Box>
                </Flex>
              ))
            ) : (
              <Text>
                We are working on course content...
              </Text>
            )}
          </Box>
        </Box>

        {/* RIGHT SIDEBAR (mobile hide handled above) */}
        <Box flex="1" display={{ base: "none", md: "block" }} />
      </Flex>

      {/* PAYMENT */}
      <Payment isOpen={isOpen} onClose={onClose} />

      <Footer />
    </>
  );
}
